import{ab as e,G as a,H as i,ad as c}from"./framework-756f1659.js";const t={},o=c('<h2 id="主从模式" tabindex="-1"><a class="header-anchor" href="#主从模式" aria-hidden="true">#</a> 主从模式</h2><p>为了避免单点故障，通常的做法是将数据库复制多个副本以部署在不同的服务器上，这样即使有一台服务器出现故障，其他服务器依然可以继续提供服务。为此， Redis 提供了复制（<code>replication</code>）功能，可以实现当一台数据库中的数据更新后，自动将更新的数据同步到其他数据库上。</p><p>在复制的概念中，数据库分为两类，一类是主数据库（<code>master</code>），另一类是从数据库(<code>slave</code>）。主数据库可以进行读写操作，当写操作导致数据变化时会自动将数据同步给从数据库。而从数据库一般是只读的，并接受主数据库同步过来的数据。一个主数据库可以拥有多个从数据库，而一个从数据库只能拥有一个主数据库。</p><figure><img src="https://iyesblogimg.oss-cn-chengdu.aliyuncs.com/img01/image-20220609214859689.png" alt="image-20220609214859689" tabindex="0" loading="lazy"><figcaption>image-20220609214859689</figcaption></figure>',4),n=[o];function d(s,r){return a(),i("div",null,n)}const _=e(t,[["render",d],["__file","index.html.vue"]]);export{_ as default};
